
// src/lib/firebase/firebase-admin.ts
import { initializeApp as initializeAdminApp, getApps as getAdminApps, type App as AdminApp } from 'firebase-admin/app';
import { getFirestore as getAdminFirestore, type Firestore as AdminFirestore, serverTimestamp, increment, doc, setDoc, getDoc, query, collection, where, getDocs } from 'firebase-admin/firestore';
import { getAuth as getAdminAuth, type Auth as AdminAuth } from 'firebase-admin/auth';
import { firebaseConfig } from './config';
import type { UserProfile } from './types';

let adminApp: AdminApp;
let adminAuth: AdminAuth;
let adminDb: AdminFirestore;

// Initialize Firebase Admin SDK
if (getAdminApps().length === 0) {
    adminApp = initializeAdminApp({
        projectId: firebaseConfig.projectId,
    });
} else {
    adminApp = getAdminApps()[0];
}

adminAuth = getAdminAuth(adminApp);
adminDb = getAdminFirestore(adminApp);

export const admin = {
  auth: adminAuth,
  db: adminDb,
  app: adminApp,
};

// Server-side database functions using Admin SDK

export async function findUserByEmail(email: string): Promise<string | null> {
    if (!email) return null;
    try {
        const userRecord = await adminAuth.getUserByEmail(email);
        return userRecord.uid;
    } catch (error: any) {
        if (error.code === 'auth/user-not-found') {
            return null;
        }
        throw error; // Re-throw other errors
    }
}

